/**
 * Toy example: Shirou's afternoon practice.
 *
 * Three objects, three outcomes:
 *   1. A wooden sword — reinforced successfully (meander through grain)
 *   2. A lightbulb — overfilled, shatters
 *   3. A diamond — peak conflict, fizzles (already at the unknot)
 */

import {
  type TargetObject,
  type ReinforcementAttempt,
  reinforce,
  diagnoseReinforcement,
  reinforcedWeight,
  perCrossingLoad,
  blindSpots,
} from "./reinforcement-topology.js";

// ── The three objects ──────────────────────────────────────────────────

const woodenSword: TargetObject = {
  crossings: 12,    // wood grain has rich internal structure
  weight: 3,        // weak as a weapon
  capacity: 20,     // wood can absorb moderate energy
  invariant: 42,    // "sword-shaped object"
};

const lightbulb: TargetObject = {
  crossings: 4,     // simple filament topology
  weight: 5,        // decent brightness
  capacity: 6,      // fragile -- very low absorption limit
  invariant: 77,    // "light-emitting object"
};

const diamond: TargetObject = {
  crossings: 0,     // perfect crystal lattice = unknot
  weight: 100,      // already extremely hard
  capacity: 50,     // high capacity but irrelevant
  invariant: 99,    // "carbon crystal"
};

// ── The attempts ───────────────────────────────────────────────────────

function attempt(name: string, target: TargetObject, energy: number): void {
  const r: ReinforcementAttempt = {
    target,
    analysis: {
      mappedCrossings: target.crossings,  // perfect structural analysis
      totalCrossings: target.crossings,
      accuracy: 100,
    },
    energy,
  };

  const diag = diagnoseReinforcement(r);
  const outcome = reinforce(r);

  console.log(`\n${"═".repeat(60)}`);
  console.log(`  ${name}`);
  console.log(`${"═".repeat(60)}`);
  console.log(`  crossings:    ${target.crossings} (internal pathways)`);
  console.log(`  weight:       ${target.weight} (current performance)`);
  console.log(`  capacity:     ${target.capacity} (max absorbable energy)`);
  console.log(`  energy:       ${energy} (mana injected)`);
  console.log(`  blind spots:  ${diag.blindSpotCount}`);
  console.log(`  per-crossing: ${diag.perCrossingLoad} energy/pathway`);
  console.log(`  ──────────────────────────────────────`);

  switch (outcome.kind) {
    case "success":
      console.log(`  OUTCOME:      SUCCESS`);
      console.log(`  new weight:   ${outcome.newWeight} (was ${target.weight})`);
      console.log(`  invariant:    ${target.invariant} (unchanged -- still the same object)`);
      break;
    case "shatter":
      console.log(`  OUTCOME:      SHATTER`);
      console.log(`  energy ${energy} > capacity ${target.capacity}`);
      console.log(`  surplus:      ${energy - target.capacity} units with no pathway`);
      console.log(`  the object explodes.`);
      break;
    case "fizzle":
      console.log(`  OUTCOME:      FIZZLE`);
      console.log(`  reason:       ${diag.reason}`);
      if (diag.reason === "peak-conflict") {
        console.log(`  zero crossings -- no internal pathways to thread energy through.`);
        console.log(`  the diamond is already at the unknot. nothing to reinforce.`);
      }
      break;
  }
}

// ── Run ────────────────────────────────────────────────────────────────

console.log(`\n  Shirou's afternoon practice\n`);

attempt("Wooden Sword (moderate energy, rich topology)", woodenSword, 15);
attempt("Lightbulb (too much energy, fragile topology)", lightbulb, 10);
attempt("Diamond (any energy, peak conflict -- zero crossings)", diamond, 30);

console.log(`\n${"═".repeat(60)}`);
console.log(`  The Hiawatha lesson:`);
console.log(`  - The sword succeeds: 12 crossings meander the energy safely.`);
console.log(`  - The bulb shatters: 10 mana through 4 crossings, capacity 6.`);
console.log(`  - The diamond fizzles: 0 crossings = no pathways = unknot.`);
console.log(`  The mage who reads the topology first knows which to attempt.`);
console.log(`${"═".repeat(60)}\n`);
